// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

interface IMarketplaceEscrow {

    enum OrderStatus {

        NONE,

        FUNDS_LOCKED,

        DISPATCHED,

        DELIVERY_CLAIMED,

        DISPUTED,

        REFUNDED,

        COMPLETED,

        CANCELLED
    }


    struct Order {

        uint256 id;

        address buyer;

        address seller;

        bytes32 listingId;

        uint256 amount;

        OrderStatus status;

        uint256 createdAt;

        uint256 dispatchedAt;

        uint256 completedAt;

        bool disputed;

        uint256 disputeId;
    }

      struct DeliveryInfo {

    // Dispatch
    string trackingId;

    string courier;

    string dispatchProofCID;

    uint256 dispatchedAt;

    // Delivery Claim
    string deliveryProofCID;

    uint256 deliveryClaimedAt;
}


    function createOrder(

        bytes32 listingId,
        address seller

    )

    external

    payable;



    function markDispatched(

    uint256 orderId,

    string calldata trackingId,

    string calldata courier,

    string calldata proofCID

)

external;


    function markDeliveryClaimed(

    uint256 orderId,

    string calldata deliveryProofCID

)

external;



    function confirmDelivery(

        uint256 orderId

    )

    external;



    function raiseDispute(

        uint256 orderId,

        string calldata reason,

        string calldata evidenceCID

    )

    external;



    function resolveDispute(

        uint256 orderId,

        bool buyerWins

    )

    external;



    function sellerClaimAfterTimeout(

        uint256 orderId

    )

    external;



    function buyerRefundAfterTimeout(

        uint256 orderId

    )

    external;



    function getOrder(

        uint256 orderId

    )

    external

    view

    returns (

        Order memory

    );
}

contracts/interfaces/ISellerBond.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

interface ISellerBond {

    struct Seller {

        bool active;

        uint256 bondedAmount;

        uint256 joinedAt;

        uint256 slashCount;
    }


    function MINIMUM_BOND()

        external

        view

        returns(uint256);



    function marketplaceEscrow()

        external

        view

        returns(address);



    function disputeManager()

        external

        view

        returns(address);



    function depositBond()

        external

        payable;



    function withdrawBond()

        external;



    function slashSeller(

        address seller,

        uint256 amount

    )

        external;



    function isSellerEligible(

        address seller

    )

        external

        view

        returns(bool);



    function getSeller(

        address seller

    )

        external

        view

        returns(

            Seller memory

        );
}

